<template><view class="page"><view class="hero"><text class="eyebrow">{{ name }}</text><text class="title">未来 7 天这样吃</text><text class="sub">菜单只是计划；点击“加入记录”后才会计入当天摄入。</text></view><view v-if="loading" class="state">正在生成菜单…</view><view v-else v-for="day in days" :key="day.id" class="day"><text class="date">{{ day.plan_date }}</text><view v-for="meal in day.meals" :key="meal.id" class="meal"><view class="meal-head"><text>{{ labels[meal.meal_type] || meal.meal_type }} · {{ meal.planned_time }}</text><text v-if="meal.recorded" class="done">已记录</text></view><view v-for="item in meal.items" :key="item.id" class="item"><text>{{ item.name }}</text><text>{{ Math.round(item.amount_g) }}g</text></view><button v-if="!meal.recorded" class="record" @tap="record(meal.id)">加入实际记录</button></view></view></view></template>
<script setup lang="ts">import { ref } from 'vue';import { onLoad,onShow } from '@dcloudio/uni-app';import { dietProgramApi,type MealPlanDay } from '@/api/diet-programs';const id=ref(0),name=ref('饮食方案'),days=ref<MealPlanDay[]>([]),loading=ref(true);const labels:Record<string,string>={breakfast:'早餐',lunch:'午餐',dinner:'晚餐',snack:'加餐'};async function load(){if(!id.value)return;loading.value=true;try{days.value=(await dietProgramApi.mealPlan(id.value)).days}catch(e:any){uni.showToast({title:e?.message||'菜单加载失败',icon:'none'})}finally{loading.value=false}}async function record(mealId:number){try{await dietProgramApi.recordMeal(mealId);uni.showToast({title:'已加入实际记录',icon:'success'});await load()}catch(e:any){uni.showToast({title:e?.message||'加入失败',icon:'none'})}}onLoad((o:any)=>{id.value=Number(o.programId);name.value=decodeURIComponent(o.name||'饮食方案');load()});onShow(load);</script>
<style scoped lang="scss">.page{min-height:100vh;padding:32rpx;background:#f7fbf8}.hero{display:flex;flex-direction:column;gap:12rpx;margin:8rpx 6rpx 28rpx}.eyebrow{font-size:25rpx;color:#34a573;font-weight:700}.title{font-size:46rpx;font-weight:800;color:#20342b}.sub{font-size:25rpx;color:#748078;line-height:1.55}.day{margin-bottom:28rpx}.date{display:block;margin:0 4rpx 14rpx;font-weight:700;color:#4d695a}.meal{background:#fff;border-radius:22rpx;padding:24rpx;margin-bottom:16rpx;box-shadow:0 8rpx 24rpx rgba(40,90,66,.06)}.meal-head,.item{display:flex;justify-content:space-between;gap:16rpx}.meal-head{font-size:30rpx;font-weight:700;color:#263a30;margin-bottom:16rpx}.item{color:#627067;font-size:27rpx;padding:10rpx 0;border-top:1rpx solid #f0f3f1}.done{color:#31a270;font-size:24rpx}.record{margin-top:18rpx;background:#e5f7ed;color:#238b5f;font-size:27rpx;border-radius:14rpx}.state{text-align:center;padding:100rpx;color:#748078}</style>
